import { Client } from "pg";
export class PgClient {
    client;
    constructor(config) {
        this.client = new Client(config);
    }
    async connect() {
        await this.client.connect();
    }
    async disconnect() {
        await this.client.end();
    }
    async query(sql, params) {
        await this.connect();
        try {
            const res = await this.client.query(sql, params);
            return res.rows;
        }
        catch (err) {
            throw err;
        }
    }
}
